export function nextGeneration(cells: Cell[]): Cell[] {
  const isAlive = (x: number, y: number): boolean =>
    cells.some(([cx, cy]) => cx === x && cy === y);

  const countNeighbors = (x: number, y: number): number =>
    NEIGHBOR_OFFSETS.filter(([dx, dy]) => isAlive(x + dx, y + dy)).length;

  const survivors = cells.filter(([x, y]) => survives(countNeighbors(x, y)));

  const deadCandidates: Cell[] = [];
  for (const [x, y] of cells) {
    for (const [dx, dy] of NEIGHBOR_OFFSETS) {
      const nx = x + dx;
      const ny = y + dy;
      if (!isAlive(nx, ny) && !deadCandidates.some(([cx, cy]) => cx === nx && cy === ny)) {
        deadCandidates.push([nx, ny]);
      }
    }
  }

  const born = deadCandidates.filter(([x, y]) => countNeighbors(x, y) === 3);

  return [...survivors, ...born];
}
